starter_code_stages:
#include <stdio.h>
#include <semaphore.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    sem_t s;
    sem_init(&s, 0, 3);        // ★ pshared=0 (intra-process), valeur initiale=3
    int val;
    sem_getvalue(&s, &val);    // ★ lire la valeur courante
    printf("Initial: %d\n", val);
    sem_wait(&s);              // ★ décrémente de 1 (bloque si val=0)
    sem_getvalue(&s, &val);
    printf("After wait: %d\n", val);
    sem_post(&s);              // ★ incrémente de 1
    sem_getvalue(&s, &val);
    printf("After post: %d\n", val);
    sem_destroy(&s);           // ★ libérer le sémaphore
    return 0;
}

